using System;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Fingerprint
{
    public static class EstatisticaForense
    {
        public static double DesvioPadrao(IEnumerable<double> valores)
        {
            var lista = valores.ToList();
            if (lista.Count < 2) return 0;

            double media = lista.Average();
            double somaQuadrados = lista.Sum(d => Math.Pow(d - media, 2));
            return Math.Sqrt(somaQuadrados / (lista.Count - 1));
        }

        public static double ZScore(double valor, double media, double desvio)
        {
            if (desvio == 0) return 0;
            return (valor - media) / desvio;
        }

        public static double DistanciaEuclidiana(double[] v1, double[] v2)
        {
            double soma = 0;
            for (int i = 0; i < v1.Length; i++)
            {
                soma += Math.Pow(v1[i] - v2[i], 2);
            }
            return Math.Sqrt(soma);
        }
    }
}

using Scriptome.Fingerprint.Interfaces;
