using System;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Fingerprint
{
    /// <summary>
    /// MOTOR DE IDENTIDADE (DOMÍNIO PURO)
    ///
    /// Responsável por:
    /// - Executar classificadores individuais
    /// - Executar Motor Etograma Cartesiano
    /// - Consolidar dados no PerfilPersonagem
    ///
    /// Sem Console.
    /// Sem efeitos colaterais externos.
    /// </summary>
    public class MotorDeIdentidade
    {
        private readonly IEnumerable<IClassificadorIndividual> _classificadoresIndividuais;
        private readonly IMotorEtogramaCartesiano _motorCartesiano;

        public MotorDeIdentidade(
            IEnumerable<IClassificadorIndividual> individuais,
            IMotorEtogramaCartesiano motorCartesiano)
        {
            _classificadoresIndividuais =
                individuais ?? throw new ArgumentNullException(nameof(individuais));

            _motorCartesiano =
                motorCartesiano ?? throw new ArgumentNullException(nameof(motorCartesiano));
        }

        public void ProcessarElenco(List<PerfilPersonagem> elenco)
        {
            if (elenco == null || !elenco.Any())
                return;

            // ===============================================================
            // 1. EXECUÇÃO INDIVIDUAL
            // ===============================================================
            foreach (var p in elenco)
            {
                if (p.Etograma == null)
                    p.Etograma = new Etograma();

                foreach (var classificador in _classificadoresIndividuais)
                {
                    try
                    {
                        classificador.Classificar(p, p.Etograma);
                    }
                    catch
                    {
                        // Domínio não faz logging.
                        // Camada superior decide como tratar.
                        throw;
                    }
                }
            }

            // ===============================================================
            // 2. MOTOR ETÓGRAMA CARTESIANO
            // ===============================================================
            foreach (var p in elenco)
            {
                try
                {
                    var etogramaCartesiano =
                        _motorCartesiano.GerarEtograma(p);

                    p.Etograma.ArquetipoNarrativoFinal =
                        etogramaCartesiano.ArquetipoNarrativoFinal;
                }
                catch
                {
                    throw;
                }
            }

            // ===============================================================
            // 3. SINCRONIZAÇÃO FINAL
            // ===============================================================
            foreach (var p in elenco)
            {
                var e = p.Etograma;

                p.ArquetipoJung = e.ArquetipoJung;
                p.ArquetipoScriptome =
                    e.ArquetipoNarrativoFinal.ToString();
                p.ArquetipoTermico = e.Termodinamica;

                p.ScoreReal = e.ScoreReal;
                p.ScoreSimbolico = e.ScoreSimbolico;
                p.ScoreImaginario = e.ScoreImaginario;

                p.RegistroDominante = e.RegistroDominante;
                p.EstruturaPsiquica = e.EstruturaPsiquica;

                p.NivelCrueldade = e.NivelCrueldade;
                p.NivelManipulacao = e.NivelManipulacao;
                p.NivelErotizacao = e.NivelErotizacao;

                p.IndicePerversidade = e.IndicePerversidade;
                p.ClassificacaoPerversidade =
                    e.ClassificacaoPerversidade;

                e.Processado = true;

                foreach (var classificador in _classificadoresIndividuais)
                {
                    //Console.WriteLine($"[MOTOR] Executando: {classificador.GetType().Name}");
                    classificador.Classificar(p, e);
                }
            }
        }

        public void ProcessarIdentidade(PerfilPersonagem p)
        {
            ProcessarElenco(new List<PerfilPersonagem> { p });

        }


    }
}

using Scriptome.Nucleo.Modelos.Fenotipo;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;

namespace Scriptome.Fingerprint
{
    /// <summary>
    /// MOTOR DE TAXONOMIA COMPORTAMENTAL (VERSÃO FENÓTIPO).
    /// Implementa UPGMA (Unweighted Pair Group Method with Arithmetic Mean).
    /// Agrupa personagens por distância comportamental consolidada.
    /// </summary>
    public class MotorTaxonomia
    {
        public string GerarArvoreFilogenetica(List<PerfilPersonagemConsolidado> fenotipos)
        {
            if (fenotipos == null || fenotipos.Count < 2)
                return "Dados insuficientes para filogenia.";

            // 1. Construir Vetores Comportamentais Consolidados
            var clusters = fenotipos.Select(f => new Cluster
            {
                Id = f.Nome,
                Membros = new List<string> { f.Nome },
                Vetor = ExtrairGenoma(f)
            }).ToList();

            var sb = new StringBuilder();
            sb.AppendLine("=== ÁRVORE FILOGENÉTICA DE COMPORTAMENTO (UPGMA) ===");

            int step = 1;

            // 2. Loop de Agrupamento
            while (clusters.Count > 1)
            {
                var (c1, c2, dist) = EncontrarParMaisProximo(clusters);

                var novoCluster = new Cluster
                {
                    Id = $"({c1.Id} + {c2.Id})",
                    Membros = c1.Membros.Concat(c2.Membros).ToList(),
                    Vetor = CalcularMediaVetorial(c1.Vetor, c2.Vetor),
                    Altura = dist / 2.0
                };

                sb.AppendLine($"Passo {step}: Fundindo {c1.Id} e {c2.Id} (Dist: {dist:F2})");

                clusters.Remove(c1);
                clusters.Remove(c2);
                clusters.Add(novoCluster);

                step++;
            }

            sb.AppendLine("\n>>> CLADO FINAL (Raiz Comportamental): " + clusters[0].Id);

            return sb.ToString();
        }

        /// <summary>
        /// Extrai o "DNA comportamental consolidado".
        /// </summary>
        private double[] ExtrairGenoma(PerfilPersonagemConsolidado f)
        {
            return new double[]
            {
                f.NivelCrueldade * 1.5,
                f.NivelManipulacao * 1.2,
                f.ScoreReal,
                f.ScoreSimbolico,
                10.0 - f.Afeto,   // Afeto invertido (frieza)
                f.Dominancia
            };
        }

        private (Cluster, Cluster, double) EncontrarParMaisProximo(List<Cluster> clusters)
        {
            Cluster bestA = null;
            Cluster bestB = null;
            double minDist = double.MaxValue;

            for (int i = 0; i < clusters.Count; i++)
            {
                for (int j = i + 1; j < clusters.Count; j++)
                {
                    double d = DistanciaEuclidiana(clusters[i].Vetor, clusters[j].Vetor);
                    if (d < minDist)
                    {
                        minDist = d;
                        bestA = clusters[i];
                        bestB = clusters[j];
                    }
                }
            }

            return (bestA, bestB, minDist);
        }

        private double DistanciaEuclidiana(double[] v1, double[] v2)
        {
            double sum = 0;
            for (int i = 0; i < v1.Length; i++)
                sum += Math.Pow(v1[i] - v2[i], 2);

            return Math.Sqrt(sum);
        }

        private double[] CalcularMediaVetorial(double[] v1, double[] v2)
        {
            var vMedia = new double[v1.Length];

            for (int i = 0; i < v1.Length; i++)
                vMedia[i] = (v1[i] + v2[i]) / 2.0;

            return vMedia;
        }

        private class Cluster
        {
            public string Id { get; set; }
            public List<string> Membros { get; set; }
            public double[] Vetor { get; set; }
            public double Altura { get; set; }
        }
    }
}

