using Scriptome.Nucleo.Modelos.Analise;
using System;

namespace Scriptome.Fingerprint.Forense
{
    /// <summary>
    /// ⚠️ LOGGER FORENSE
    /// 
    /// Usado apenas para validação experimental.
    /// NÃO deve ser usado em execução produtiva.
    /// </summary>
    public static class DivergenceLogger
    {
        public static void Avaliar(PerfilPersonagem perfil)
        {
            if (perfil?.IdentidadeRNA == null)
                return;

            Console.ForegroundColor = ConsoleColor.DarkCyan;
            Console.WriteLine($"\n[FORENSE RNA CHECK] {perfil.Nome}");
            Console.ResetColor();

            LogLinha("JUNG", perfil.ArquetipoJung, perfil.IdentidadeRNA.Jung?.Individual);
            LogLinha("LACAN", perfil.EstruturaPsiquica, perfil.IdentidadeRNA.Lacan?.EstruturaPsiquica);
            LogLinha("MBTI", perfil.Etograma?.TipoMbti, perfil.IdentidadeRNA.Mbti?.Tipo);
            LogLinha("NARRATIVO", perfil.ArquetipoScriptome, perfil.IdentidadeRNA.Narrativa?.ArquetipoScriptome);

            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.WriteLine($"SCORE: {perfil.DivergenceScoreRNA:F2}");
            Console.ResetColor();
        }

        private static void LogLinha(string eixo, string? legado, string? rna)
        {
            legado ??= "-";
            rna ??= "-";

            if (string.Equals(legado, rna, StringComparison.OrdinalIgnoreCase))
                Console.ForegroundColor = ConsoleColor.DarkGreen;
            else
                Console.ForegroundColor = ConsoleColor.DarkYellow;

            Console.WriteLine($"{eixo.PadRight(12)} {legado.PadRight(15)} | {rna}");
            Console.ResetColor();
        }
    }
}

using Scriptome.Nucleo.Modelos.Analise;
using System;

namespace Scriptome.Fingerprint.Forense
{
    /// <summary>
    /// ⚠️ MÓDULO FORENSE
    /// 
    /// Usado apenas para validação científica do Strangler.
    /// NÃO deve ser utilizado em runtime produtivo.
    /// </summary>
    public static class DivergenceScore
    {
        public static double Calcular(PerfilPersonagem perfil)
        {
            if (perfil?.IdentidadeRNA == null)
                return 0;

            double score = 0;
            int total = 0;

            total++;
            if (!string.Equals(
                perfil.ArquetipoJung,
                perfil.IdentidadeRNA.Jung?.Individual,
                StringComparison.OrdinalIgnoreCase))
                score++;

            total++;
            if (!string.Equals(
                perfil.EstruturaPsiquica,
                perfil.IdentidadeRNA.Lacan?.EstruturaPsiquica,
                StringComparison.OrdinalIgnoreCase))
                score++;

            total++;
            if (!string.Equals(
                perfil.Etograma?.TipoMbti,
                perfil.IdentidadeRNA.Mbti?.Tipo,
                StringComparison.OrdinalIgnoreCase))
                score++;

            total++;
            if (!string.Equals(
                perfil.ArquetipoScriptome,
                perfil.IdentidadeRNA.Narrativa?.ArquetipoScriptome,
                StringComparison.OrdinalIgnoreCase))
                score++;

            return total == 0 ? 0 : score / total;
        }
    }
}

