namespace Scriptome.Fingerprint.Modelos
{
    /// <summary>
    /// O Boletim de Identidade do Personagem.
    /// v4.2: Compatível com Psicodinâmica tridimensional de Intenção.
    /// Mantém compatibilidade com v4.1.
    /// </summary>
    public class Etograma
    {
        public bool Processado { get; set; } = false;

        // --- Camada 1: Psicologia Clássica ---
        public string ArquetipoJung { get; set; } = "Indefinido";

        // --- Camada 2: Lógica Proprietária ---
        public string ArquetipoScriptome { get; set; } = "Indefinido";

        // --- Camada 3: Vetorial Matemática ---
        public string ArquetipoDavm { get; set; } = "Indefinido";
        public string TipoMbti { get; set; } = "XXXX";
        public double ConflitoDavm { get; set; }

        // --- Camada 4: Física Elemental ---
        public string Termodinamica { get; set; } = "Neutro";

        // --- Camada 5: Bússola Moral ---
        public string AlinhamentoMoral { get; set; } = "Neutro";

        // --- Camada 6: PSICANÁLISE LACANIANA (R.S.I.) ---

        // Intensidade estrutural (0–10)
