namespace Scriptome.Fingerprint.MotoresEtograma
{
    /// <summary>
    /// MOTOR ETOGRAMA V2
    ///
    /// Pipeline sequencial dependente.
    /// Cada classificador recebe o estado acumulado.
    /// Produz ResultadoEtograma imutável.
    /// </summary>
    public sealed class MotorEtogramaV2
    {
        private readonly IList<IClassificadorEtogramaV2> _classificadores;

        public MotorEtogramaV2(
            IEnumerable<IClassificadorEtogramaV2> classificadores)
        {
            _classificadores = classificadores
                .ToList();
        }

        public ResultadoEtograma Gerar(
            PerfilPersonagem personagem)
        {
            if (personagem == null)
                throw new ArgumentNullException(nameof(personagem));

            var acumulado = new ParcialEtograma();

            foreach (var classificador in _classificadores)
            {
                var parcial =
                    classificador.Executar(
                        personagem,
                        acumulado);

                acumulado = Mesclar(acumulado, parcial);
            }

            return Consolidar(acumulado);
        }

        // ==========================================
        // MESCLAGEM DE PARCIAIS
        // ==========================================

        private ParcialEtograma Mesclar(
            ParcialEtograma atual,
            ParcialEtograma novo)
        {
            return atual with
            {
                ArquetipoNarrativoFinal =
                    novo.ArquetipoNarrativoFinal ?? atual.ArquetipoNarrativoFinal,

                ArquetipoJung =
                    novo.ArquetipoJung ?? atual.ArquetipoJung,

                IntensidadeImaginario =
                    novo.IntensidadeImaginario ?? atual.IntensidadeImaginario,

                IntensidadeSimbolico =
                    novo.IntensidadeSimbolico ?? atual.IntensidadeSimbolico,

                IntensidadeReal =
                    novo.IntensidadeReal ?? atual.IntensidadeReal,

                ScoreImaginario =
                    novo.ScoreImaginario ?? atual.ScoreImaginario,

                ScoreSimbolico =
                    novo.ScoreSimbolico ?? atual.ScoreSimbolico,

                ScoreReal =
                    novo.ScoreReal ?? atual.ScoreReal,

                RegistroDominante =
                    novo.RegistroDominante ?? atual.RegistroDominante,

                EstruturaPsiquica =
                    novo.EstruturaPsiquica ?? atual.EstruturaPsiquica,

                IntensidadeDiscursiva =
                    novo.IntensidadeDiscursiva ?? atual.IntensidadeDiscursiva,

                ClassificacaoIntensidade =
                    novo.ClassificacaoIntensidade ?? atual.ClassificacaoIntensidade,

                Termodinamica =
                    novo.Termodinamica ?? atual.Termodinamica,

                NivelCrueldade =
                    novo.NivelCrueldade ?? atual.NivelCrueldade,

                NivelManipulacao =
                    novo.NivelManipulacao ?? atual.NivelManipulacao,

                NivelErotizacao =
                    novo.NivelErotizacao ?? atual.NivelErotizacao,

                IndicePerversidade =
                    novo.IndicePerversidade ?? atual.IndicePerversidade,

                ClassificacaoPerversidade =
                    novo.ClassificacaoPerversidade ?? atual.ClassificacaoPerversidade,

                TipoMbti =
                    novo.TipoMbti ?? atual.TipoMbti,

                PerfilHibrido =
                    novo.PerfilHibrido ?? atual.PerfilHibrido
            };
        }

        // ==========================================
        // CONSOLIDAÇÃO FINAL
        // ==========================================

        private ResultadoEtograma Consolidar(
            ParcialEtograma p)
        {
            var arq =
                p.ArquetipoNarrativoFinal ??
                ArquetipoNarrativo.Indefinido;

            return new ResultadoEtograma(
                ArquetipoNarrativoFinal: arq,
                ArquetipoJung: p.ArquetipoJung ?? "Indefinido",
                CategoriaNarrativa:
                    BibliotecaArquetipos.ObterCategoria(arq),

                IntensidadeImaginario: p.IntensidadeImaginario ?? 0,
                IntensidadeSimbolico: p.IntensidadeSimbolico ?? 0,
                IntensidadeReal: p.IntensidadeReal ?? 0,

                ScoreImaginario: p.ScoreImaginario ?? 0,
                ScoreSimbolico: p.ScoreSimbolico ?? 0,
                ScoreReal: p.ScoreReal ?? 0,

                RegistroDominante: p.RegistroDominante ?? "Indefinido",
                EstruturaPsiquica: p.EstruturaPsiquica ?? "Indefinida",

                IntensidadeDiscursiva: p.IntensidadeDiscursiva ?? 0,
                ClassificacaoIntensidade: p.ClassificacaoIntensidade ?? "Indefinida",
                Termodinamica: p.Termodinamica ?? "Neutro",

                NivelCrueldade: p.NivelCrueldade ?? 0,
                NivelManipulacao: p.NivelManipulacao ?? 0,
                NivelErotizacao: p.NivelErotizacao ?? 0,
                IndicePerversidade: p.IndicePerversidade ?? 0,
                ClassificacaoPerversidade:
                    p.ClassificacaoPerversidade ?? "Indefinida",

                TipoMbti: p.TipoMbti ?? "XXXX",
                PerfilHibrido: p.PerfilHibrido ?? "Indefinido"
            );
        }
    }
}

