using Scriptome.Fingerprint.Interfaces;
using Scriptome.Fingerprint.Modelos;
using Scriptome.Nucleo.Modelos.Analise;
using Scriptome.Fingerprint; // Para EstatisticaForense
using System;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Fingerprint.Classificadores.Arquetipos
{
    public class ClassificadorJung : IClassificadorIndividual
    {
        public string Nome => "Psicologia Analítica (Jung Híbrido)";

        public void Classificar(PerfilPersonagem p, Etograma e)
        {
            // Fallback Absoluto (Garante que nunca fique vazio)
            double ext = (p.ScoreDominancia + p.ScoreVolicao) / 2.0;
            e.ArquetipoJung = ext > 5.0 ? (p.ScoreAfeto > 5.0 ? "Herói" : "Guerreiro") : "Sábio";
        }

        public void ClassificarElenco(List<PerfilPersonagem> elenco)
        {
            if (elenco == null || !elenco.Any()) return;

            // 1. Médias de Extroversão (Atividade) e Sentimento (Afeto)
            var scoreExt = elenco.Select(x => x.ScoreDominancia + x.ScoreVolicao).ToList();
            var scoreAfe = elenco.Select(x => x.ScoreAfeto).ToList();

            double mExt = scoreExt.Average(); double dExt = EstatisticaForense.DesvioPadrao(scoreExt);
            double mAfe = scoreAfe.Average(); double dAfe = EstatisticaForense.DesvioPadrao(scoreAfe);

            foreach (var p in elenco)
            {
                double zExt = EstatisticaForense.ZScore(p.ScoreDominancia + p.ScoreVolicao, mExt, dExt);
                double zAfe = EstatisticaForense.ZScore(p.ScoreAfeto, mAfe, dAfe);

                // Quadrantes de Jung (Z-Score)
                if (zExt > 0) // Extrovertido (Acima da média do elenco)
                {
                    p.Etograma.ArquetipoJung = zAfe > 0 ? "Governante / Herói" : "Rebelde / Fora da Lei";
                }
                else // Introvertido (Abaixo da média do elenco)
                {
                    p.Etograma.ArquetipoJung = zAfe > 0 ? "Amante / Inocente" : "Sábio / Eremita";
                }

                p.ArquetipoJung = p.Etograma.ArquetipoJung;
            }
        }
    }
}

using Scriptome.Fingerprint.Interfaces;
using Scriptome.Fingerprint.Modelos;
using Scriptome.Nucleo.Interfaces;
using Scriptome.Nucleo.Modelos.Genoma;
using System;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Fingerprint.Classificadores.Arquetipos
{
    public sealed class ClassificadorJungV2 : IClassificadorJungV2
    {
        private readonly IMotorSplicing _splicing;

        public ClassificadorJungV2(IMotorSplicing splicing)
        {
            _splicing = splicing;
        }

        // ===============================
        // INDIVIDUAL
        // ===============================
        public ResultadoJung Classificar(RnaBruto rna)
        {
            var fatia = _splicing.Extrair(rna, "D", "V", "A");

            double ext = (fatia.Get("D") + fatia.Get("V")) / 2.0;

            string arquétipo =
                ext > 5.0
                ? (fatia.Get("A") > 5.0 ? "Herói" : "Guerreiro")
                : "Sábio";

            return new ResultadoJung(arquétipo);
        }

        // ===============================
        // ELENCO (Z-SCORE)
        // ===============================
        public Dictionary<RnaBruto, ResultadoJung> ClassificarElenco(
            IReadOnlyList<RnaBruto> elenco)
        {
            var resultado = new Dictionary<RnaBruto, ResultadoJung>();

            if (elenco == null || elenco.Count == 0)
                return resultado;

            var extList = elenco
                .Select(r =>
                {
                    var f = _splicing.Extrair(r, "D", "V");
                    return f.Get("D") + f.Get("V");
                })
                .ToList();

            var afeList = elenco
                .Select(r =>
                {
                    var f = _splicing.Extrair(r, "A");
                    return f.Get("A");
                })
                .ToList();

            double mExt = extList.Average();
            double dExt = DesvioPadrao(extList);

            double mAfe = afeList.Average();
            double dAfe = DesvioPadrao(afeList);

            for (int i = 0; i < elenco.Count; i++)
            {
                var rna = elenco[i];

                double ext = extList[i];
                double afe = afeList[i];

                double zExt = ZScore(ext, mExt, dExt);
                double zAfe = ZScore(afe, mAfe, dAfe);

                string coletivo;

                if (zExt > 0)
                {
                    coletivo = zAfe > 0
                        ? "Governante / Herói"
                        : "Rebelde / Fora da Lei";
                }
                else
                {
                    coletivo = zAfe > 0
                        ? "Amante / Inocente"
                        : "Sábio / Eremita";
                }

                resultado[rna] = new ResultadoJung(
                    individual: Classificar(rna).Individual,
                    coletivo: coletivo);
            }

            return resultado;
        }

        // ===============================
        // ESTATÍSTICA INTERNA
        // ===============================
        private double DesvioPadrao(List<double> valores)
        {
            if (valores.Count < 2) return 0;

            double media = valores.Average();
            double soma = valores.Sum(v => Math.Pow(v - media, 2));
            return Math.Sqrt(soma / valores.Count);
        }

        private double ZScore(double valor, double media, double desvio)
        {
            if (desvio < 0.0001) return 0;
            return (valor - media) / desvio;
        }
    }
}

