using Scriptome.Fingerprint.Interfaces;
using Scriptome.Fingerprint.Modelos;
using Scriptome.Nucleo.Modelos.Analise;
using System;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Fingerprint.Classificadores.Psique
{
    public class ClassificadorLacaniano : IClassificadorIndividual
    {
        public string Nome => "Topologia Lacaniana (R.S.I. Estrutural)";

        public void Classificar(PerfilPersonagem p, Etograma e)
        {
            // ===============================
            // 1. CÁLCULO ESTRUTURAL (LEGADO PRESERVADO)
            // ===============================

            double intensidadeI = (p.ScoreEgo * 2.0 + p.ScoreSensorium + p.ScoreAfeto) / 4.0;

            double ordemNorm = Math.Clamp((p.KarmaOrdem + 100) / 20.0, 0, 10);
            double intensidadeS = (p.ScoreRacionalidade * 1.5 + p.ScoreErudicao + ordemNorm) / 3.5;

            double burstNorm = Math.Clamp(p.BurstMedio / 5.0, 0, 10);
            double intensidadeR = (p.ScoreVolicao * 2.0 + p.ScoreDominancia + burstNorm) / 4.0;

            // Preserva intensidade estrutural
            e.IntensidadeImaginario = Math.Round(intensidadeI, 2);
            e.IntensidadeSimbolico = Math.Round(intensidadeS, 2);
            e.IntensidadeReal = Math.Round(intensidadeR, 2);

            // ===============================
            // 2. NORMALIZAÇÃO RELATIVA
            // ===============================

            double total = intensidadeI + intensidadeS + intensidadeR;

            if (total <= 0.01)
            {
                e.ScoreImaginario = 0;
                e.ScoreSimbolico = 0;
                e.ScoreReal = 0;
                e.RegistroDominante = "INDEFINIDO";
                e.EstruturaPsiquica = "Indeterminada";
                return;
            }

            e.ScoreImaginario = Math.Round((intensidadeI / total) * 10, 2);
            e.ScoreSimbolico = Math.Round((intensidadeS / total) * 10, 2);
            e.ScoreReal = Math.Round((intensidadeR / total) * 10, 2);

            // ===============================
            // 3. REGISTRO DOMINANTE
            // ===============================

            var registros = new Dictionary<string, double>
            {
                { "IMAGINÁRIO", e.ScoreImaginario },
                { "SIMBÓLICO", e.ScoreSimbolico },
                { "REAL", e.ScoreReal }
            };

            if (registros.Values.Distinct().Count() == 1)
                e.RegistroDominante = "EQUILIBRADO";
            else
                e.RegistroDominante = registros
                    .OrderByDescending(x => x.Value)
                    .First().Key;

            // ===============================
            // 4. DIAGNÓSTICO CLÍNICO
            // ===============================

            e.EstruturaPsiquica = DiagnosticarClinico(
                e.RegistroDominante,
                e.IntensidadeReal,
                e.IntensidadeSimbolico
            );
        }

        private string DiagnosticarClinico(string dominante, double intensidadeReal, double intensidadeSimbolico)
        {
            // Psicose → Real estrutural alto + Simbólico estrutural baixo
            if (intensidadeReal > 6 && intensidadeSimbolico < 3)
                return "Psicose (Foraclusão)";

            if (dominante == "IMAGINÁRIO")
                return "Neurose Histérica";

            if (dominante == "SIMBÓLICO")
                return "Neurose Obsessiva";

            if (dominante == "REAL")
                return "Estrutura Pulsional";

            return "Estrutura Limítrofe";
        }
    }
}

using Scriptome.Fingerprint.Interfaces;
