            if (elenco == null || elenco.Count == 0)
                return resultado;

            foreach (var rna in elenco)
                resultado[rna] = Classificar(rna);

            return resultado;
        }

        private double RSI(double a, double b)
        {
            double denom = Math.Abs(a) + Math.Abs(b);
            if (denom < 0.0001) return 0;
            return (a - b) / denom;
        }
    }
