/// <summary>
/// CLASSIFICADOR PSICODINÂMICO (LACAN + KARMA + BURST).
/// Objetivo: Gerar um rótulo psicológico legível e acionável para roteiristas.
/// Baseado na tríade Lacaniana (Imaginário, Simbólico, Real) com ajustes de Karma e Burst.
/// </summary>
/// 

using Scriptome.Fingerprint.Interfaces;
using Scriptome.Fingerprint.Modelos;
using Scriptome.Nucleo.Modelos.Analise;
using System;

namespace Scriptome.Fingerprint.Classificadores.Psique
{
    public class ClassificadorPsicodinamico : IClassificadorIndividual
    {
        public string Nome => "Psicodinâmica Instrumental";

        public void Classificar(PerfilPersonagem p, Etograma e)
        {
            // INTENÇÃO
            e.IntencaoCognitiva = Math.Round(
                (p.ScoreRacionalidade * 0.6) +
                (p.ScoreErudicao * 0.4), 1);

            e.IntencaoMotora = Math.Round(
                (p.ScoreVolicao * 0.7) +
                (p.ScoreDominancia * 0.3), 1);

            e.IntencaoEmocional = Math.Round(
                p.ScoreAfeto, 1);

            // PERVERSIDADE
            double faltaAfeto = Math.Max(0, 10 - p.ScoreAfeto);

            e.NivelCrueldade = Math.Round(
                (p.ScoreDominancia * 0.5) +
                (p.ScoreEgo * 0.2) +
                (faltaAfeto * 0.3), 1);

            e.NivelManipulacao = Math.Round(
                (p.ScoreRacionalidade * 0.4) +
                (p.ScoreIronia * 0.3) +
                (p.ScoreDominancia * 0.3), 1);

            e.NivelErotizacao = Math.Round(
                (p.ScoreSensorium * 0.4) +
                (p.ScoreDominancia * 0.3) +
                (p.ScoreVolicao * 0.3), 1);

            e.IndicePerversidade = Math.Round(
                (e.NivelCrueldade * 0.5) +
                (e.NivelManipulacao * 0.3) +
                (e.NivelErotizacao * 0.2), 1);
        }
    }
}

public class ClassificadorPsicodinamicoAvancado: IClassificadorIndividual
{
    public string Nome => "Psicodinâmica Lacaniana Avançada";

    public void Classificar(PerfilPersonagem p, Etograma e)
    {
        double ordem = Math.Clamp((p.KarmaOrdem + 100) / 20.0, 0, 10);
        double burst = Math.Clamp(p.BurstMedio / 5.0, 0, 10);

        double I =
            p.ScoreEgo * 0.5 +
            p.ScoreSensorium * 0.25 +
            p.ScoreAfeto * 0.25;

        double S =
            p.ScoreRacionalidade * 0.4 +
            p.ScoreErudicao * 0.3 +
            ordem * 0.3;

        double Rbase =
            p.ScoreVolicao * 0.5 +
            p.ScoreDominancia * 0.5;

        double R = Rbase + Math.Sqrt(burst) * 0.6;

        I = Math.Clamp(I, 0, 10);
        S = Math.Clamp(S, 0, 10);
        R = Math.Clamp(R, 0, 10);

        e.IntensidadeImaginario = I;
        e.IntensidadeSimbolico = S;
        e.IntensidadeReal = R;

        double max = Math.Max(I, Math.Max(S, R)) + 0.0001;

        e.ScoreImaginario = Math.Round(I / max * 10, 2);
        e.ScoreSimbolico = Math.Round(S / max * 10, 2);
        e.ScoreReal = Math.Round(R / max * 10, 2);

        double media = (I + S + R) / 3.0;
        double variancia =
            (Math.Pow(I - media, 2) +
             Math.Pow(S - media, 2) +
             Math.Pow(R - media, 2)) / 3.0;

        e.RegistroDominante = variancia < 0.35
            ? "EQUILIBRADO"
            : new[] { ("IMAGINÁRIO", I), ("SIMBÓLICO", S), ("REAL", R) }
                .OrderByDescending(x => x.Item2)
                .First().Item1;

        double razaoRS = R / (S + 0.01);

        if (razaoRS > 1.4)
            e.EstruturaPsiquica = "Psicose (Foraclusão)";
        else if (e.RegistroDominante == "SIMBÓLICO")
            e.EstruturaPsiquica = "Neurose Obsessiva";
        else if (e.RegistroDominante == "IMAGINÁRIO")
            e.EstruturaPsiquica = "Neurose Histérica";
        else if (e.RegistroDominante == "REAL" && media > 5)
            e.EstruturaPsiquica = "Estrutura Pulsional";
        else
            e.EstruturaPsiquica = "Estrutura Limítrofe";
    }
}

